const kpi = $('HTTP — Fetch KPIs').first().json;
const newLeadsRes = $('HTTP — Leads novos hoje').first().json;

const offmarket = kpi.offmarket || {};
const partners = kpi.institutional_partners || {};
const newLeads = (newLeadsRes.data || []).slice(0, 5);

// Top leads list
const topList = newLeads.map((l, i) => 
  `${i+1}. ${l.nome} — ${l.tipo_ativo || '?'} ${l.cidade ? '(' + l.cidade + ')' : ''} — Score: ${l.score ?? 'pendente'}`
).join('\n');

// Cadence recommendation
const totalActive = offmarket.active || 0;
const dailyTarget = Math.min(20, Math.ceil(totalActive * 0.15));

return [{ json: {
  total: offmarket.total || 0,
  new_this_week: offmarket.new_this_week || 0,
  high_score: offmarket.high_score || 0,
  pending_score: offmarket.pending_score || 0,
  avg_score: offmarket.avg_score ? parseFloat(offmarket.avg_score).toFixed(0) : '—',
  partners_total: partners.total || 0,
  partners_new: partners.new_this_week || 0,
  top_leads_list: topList || '— sem leads novos —',
  daily_target: dailyTarget,
  date: new Date().toLocaleDateString('pt-PT', { weekday: 'long', day: 'numeric', month: 'long' })
}}];
